import type { AppNavItem } from "../../componentTypes/appNavItem"
import type { Semantics } from "../semantics"

const appNavItem = (semantics: Semantics): AppNavItem => ({
  fontFamily: semantics.fontFamily.base,
  backgroundColor: semantics.color.background.elevatedSurface.base,
  fontWeight: semantics.fontWeight.body.strong,
  height: "2.25rem",
  padding: semantics.spacing.padding.container.xs,
  textColor: semantics.color.text.accent.blue,
  textColorSelected: semantics.color.text.accent.ash,
  fontSize: "1.125rem",
})
export default appNavItem
